#include <bits/stdc++.h>
using namespace std;
const int N=1003,mod=2015;
int n,k,f[N][N];
int main(){
    scanf("%d%d",&n,&k);
    f[0][0]=1;
    for(int i=1;i<=n;i++){
        f[i][0]=1;
        for(int j=1;j<i;j++)
            f[i][j]=(f[i-1][j]*(j+1)%mod+f[i-1][j-1]*(i-j)%mod)%mod;
    }
    printf("%d",f[n][k]);
    return 0;
}
